# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import json
from typing import Dict, List

import aiohttp
import aiohttp_websocket

class Player:
    def __init__(self, id: int, inventory: Dict[str, int] = {}):
        self.id = id
        self.inventory = inventory

    async def send(self, message: str):
        await self.ws.send(message)

class InventoryServer:
    def __init__(self, port: int):
        self.players = {}
        self.port = port

    async def on_player_connected(self, player: Player, ws: aiohttp_websocket.WebSocket):
        self.players[player.id] = (player, ws)
        await player.send(f"Connected as player {player.id}")
        print(f"Player {player.id} connected.")

    async def on_player_message(self, player: Player, message: str):
        action, data = json.loads(message)
        if action == "trade":
            to_id, item_name, quantity = data
            target_player = self.players.get(to_id)
            if target_player:
                trade(player, target_player, item_name, quantity)
                await player.send(f"Traded {quantity} of {item_name}")
                await target_player[1].send(f"Traded {quantity} of {item_name}")
            else:
                await player.send("Target player not found.")

    async def on_player_disconnected(self, player: Player):
        self.players.pop(player.id)
        print(f"Player {player.id} disconnected.")

    async def start(self):
        app = aiohttp.web.Application()
        runner = aiohttp_websocket.WebSocketHandler(self.on_player_connected, self.on_player_message)
        app.router.add_route("*", "/ws", runner)
        web_app = aiohttp.web.serve_web_socket(runner, app)
        await app.start(self.port)
        print(f"Server started on port {self.port}")
        while True:
            await asyncio.sleep(1)

def trade(sender_player: Player, receiver_player: Player, item_name: str, quantity: int):
    if item_name in sender_player.inventory and quantity <= sender_player.inventory[item_name]:
        sender_player.inventory[item_name] -= quantity
        receiver_player.inventory[item_name] += quantity
    else:
        sender_player.send("Not enough items for trade.")

if __name__ == "__main__":
    server = InventoryServer(port=8080)
    asyncio.run(server.start())